import os,glob,pandas as pd
paths=glob.glob('/workspace/**/*.*',recursive=True)
paths=[p for p in paths if os.path.splitext(p)[1].lower() in ['.csv','.xlsx','.xls','.ods']]
print('CANDIDATES:')
for p in paths: print(p)
for p in paths[:5]:
    print('\n===',p,'===')
    try:
        if p.lower().endswith('.csv'):
            df=pd.read_csv(p,nrows=20)
        else:
            df=pd.read_excel(p,nrows=20)
        print('shape_preview',df.shape)
        print('columns',list(df.columns))
        print(df.head(5).to_string(index=False))
    except Exception as e:
        print('preview_error',e)
